<script src="https://cdn.jsdelivr.net/npm/bootstrap@5.3.0/dist/js/bootstrap.bundle.min.js"></script><script>const codeInput=document.querySelector('input[name="code"]');codeInput.addEventListener('input',()=>{codeInput.value=codeInput.value.replace(/\D+/g,'').slice(0,6);});document.getElementById('resetForm').addEventListener('submit',e=>{e.preventDefault();codeInput.value=codeInput.value.replace(/\D+/g,'').slice(0,6);fetch('backend.php',{method:'POST',body:new FormData(e.target)}).then(r=>r.json()).then(d=>{document.getElementById('msg').textContent=d.message||'';if(d.success&&d.redirect)setTimeout(()=>location.href=d.redirect,900);});});</script></body></html>
